import React from 'react'
import { Container, Nav, Navbar } from 'react-bootstrap';
import {
  BrowserRouter as Router,
  Route,
  Link
} from "react-router-dom";
import './App.css';

import Footer from './components/Footer';
import AboutPage from './pages/AboutPage';
import HomePage from './pages/HomePage';

class App extends React.Component {

  constructor(props) {
    super(props);
    this.state = {
      title: 'Kaid Sadikot',
      headerLinks: [
        { title: 'Home', path: '/portfolio/' },
        { title: 'About', path: '/about' },
      ],
      home: {
        title: 'Welcome to my website',
        subtitle: "This is what I've done"
      },
      about: {
        title: 'About Me',

      }
    }
  }
  render() {
    return (
      <Router>
        <Container className="p-0" fluid>

          <Navbar className="border-bottom" bg="transparent" expand="lg">
            <Navbar.Brand>Kaid Sadikot</Navbar.Brand>

            <Navbar.Toggle className="border-0" aria-controls="navbar-toggle" />
            <Navbar.Collapse id="navbar-toggle">
              <Nav className="ml-auto">
                <Link className="nav-link" to="/portfolio/">Home</Link>
                <Link className="nav-link" to="/about">About</Link>


              </Nav>
            </Navbar.Collapse>
          </Navbar>

          <Route path="/portfolio/" exact render={() => <HomePage title={this.state.home.title} subtitle={this.state.home.subtitle} />} />
          <Route path="/about" exact render={() => <AboutPage title={this.state.about.title} />} />

          <Footer />

        </Container>

      </Router>

    );
  }



}

export default App;
